function q(o){let t=[...o].sort((s,i)=>s-i),n=t.length,r=m(t),e=t.slice(0,Math.floor(n/2)),f=n%2===0?t.slice(Math.floor(n/2)):t.slice(Math.floor(n/2)+1),h=m(e),c=m(f);return{q1:h,q2:r,q3:c}}function m(o){let t=[...o].sort((r,e)=>r-e),n=t.length;return n%2===0?(t[n/2-1]+t[n/2])/2:t[Math.floor(n/2)]}function g(o){return o.reduce((t,n)=>t+n,0)/o.length}function x(o){let t=g(o),n=o.map(r=>Math.pow(r-t,2));return Math.sqrt(g(n))}function w(o,t=10){let n=Math.min(...o),e=(Math.max(...o)-n)/t,f=[],h=new Array(t).fill(0),c=[];for(let s=0;s<=t;s++)c.push(n+s*e);o.forEach(s=>{let i=Math.min(Math.floor((s-n)/e),t-1);h[i]++});for(let s=0;s<t;s++)f.push((c[s]+c[s+1])/2);return{bins:f,counts:h,binEdges:c}}function y(o,t,n=100){let r=[...o].sort((l,a)=>l-a),e=r[0],h=r[r.length-1]-e,c=t||1.06*x(o)*Math.pow(o.length,-1/5),s=[],i=[];for(let l=0;l<n;l++){let a=e+h*l/(n-1);s.push(a);let u=0;o.forEach(p=>{let M=(a-p)/c;u+=Math.exp(-.5*M*M)/Math.sqrt(2*Math.PI)}),u/=o.length*c,i.push(u)}return{x:s,y:i}}export{q as a,w as b,y as c};
